def det_recursive(A):
    n = len(A)
    if any(len(row) != n for row in A):
        raise ValueError("Matrix must be square")
    if n == 1:
        return float(A[0][0])
    if n == 2:
        return float(A[0][0] * A[1][1] - A[0][1] * A[1][0])
    result = 0.0
    for j in range(n):
        # Minor: delete row 0 and column j
        minor = [[A[i][k] for k in range(n) if k != j] for i in range(1, n)]
        cofactor = ((-1) ** j) * det_recursive(minor)
        result += A[0][j] * cofactor
    return result


import numpy as np

def det_lu(A):
    A = np.asarray(A, dtype=float).copy()
    n = A.shape[0]
    sign = 1

    for col in range(n):
        # Partial pivoting
        pivot_row = col + np.argmax(np.abs(A[col:, col]))
        if pivot_row != col:
            A[[col, pivot_row]] = A[[pivot_row, col]]
            sign *= -1
        if abs(A[col, col]) < 1e-15:
            return 0.0  # singular
        for row in range(col + 1, n):
            factor = A[row, col] / A[col, col]
            A[row, col:] -= factor * A[col, col:]

    return float(sign * np.prod(np.diag(A)))
